/**
 * The FFI entry point. One per app; `begin_session`/`begin_initiation`
 * (`session.rs`) hand out per-session `SessionHandle`s.
 */
public protocol AthanorEngineProtocol: AnyObject, Sendable {
    
    /**
     * The Furnace read: held heat + days tended (`Store::fire_state`).
     */
    func furnaceState() throws  -> FurnaceState
    
    /**
     * The Grimoire read: every fixed grain of salt, chronological
     * (`Store::list_realizations`).
     */
    func grimoire() throws  -> [GrimoireGrain]
    
    /**
     * The home screen's per-door heat (lane 14): every door's 0..1 temperature,
     * computed in core from real store facts (`Store::home_heat`). Heat is the
     * notification system — no badges or counts anywhere.
     */
    func homeHeat() throws  -> HomeHeat
    
    /**
     * The Mercury read: open threads (volatile + condensing)
     * (`Store::open_threads`), each with its domain's human NAME resolved from
     * the domain table so the UI never has to show a raw domain id.
     */
    func mercury() throws  -> [OpenThread]
    
    /**
     * The single most recent closed session, or `None` — the cheap read the
     * resume surface reopens from.
     */
    func mostRecentSession() throws  -> SessionSummary?
    
    /**
     * The most recent closed sessions regardless of thread — the "past fires"
     * surface (also reaches threadless sessions: initiation, bare opens).
     * `offset` paginates (0 = newest page) for the resume lane's scroll-back.
     */
    func recentSessions(limit: UInt32, offset: UInt32) throws  -> [SessionSummary]
    
    /**
     * One session's full detail — the role-tagged transcript (both sides) plus
     * its condensation note — for the reading view.
     */
    func sessionDetail(sessionId: String) throws  -> SessionDetail
    
    /**
     * Closed sessions on a thread, newest first — the thread-detail view's
     * history (tapping a Mercury thread shows every fire tended on it).
     */
    func sessionsForThread(threadId: String) throws  -> [SessionSummary]
    
    /**
     * The Tabula read: the seven canonical passages (number/title/body)
     * projected against this learner's kindling state (`Store::tabula`).
     * Always seven, in scroll order — dim until the learner's practice lights
     * them.
     */
    func tabula() throws  -> [TabulaPassage]
    
    /**
     * Opens the first-launch initiation session (cold start).
     */
    func beginInitiation() throws  -> SessionHandle
    
    /**
     * Opens an ordinary session against `(mask, mode, thread_id)` — each
     * `None` falls back to the default voice/mode/no-thread. Fallible across
     * FFI (no panic): a store error surfaces as `EngineError::Session`.
     */
    func beginSession(mask: String?, mode: String?, threadId: String?) throws  -> SessionHandle
    
}
