// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * One streamed update from a session, projected for the Swift shell.
 */

public enum SessionEvent: Equatable, Hashable {
    
    /**
     * A chunk of the Mystagogue's reply text, tagged with the register it is
     * spoken in. The core's `Conductor` parses the model's reading-voice
     * markers (identity.md §6), strips them, and tags each run — so `register`
     * here is a real signal from core, never a bridge default.
     */
    case textDelta(text: String, register: ReplyRegister
    )
    /**
     * The engine invoked a Mystagogue tool this turn; `kind` is the tool name
     * (`fix_salt`, `open_thread`, `evaporate_thread`, `kindle_passage`,
     * `weave_domains`, `update_memory`).
     */
    case toolCall(kind: String
    )
    /**
     * **Bridge-synthesized.** The session's current `(mask, mode)` register
     * (lane 13) — emitted at the top of a turn whenever it differs from what was
     * last surfaced: the opening pair on the first turn, and the new pair on the
     * first turn after a `shift_mask` (or a learner pin). Drives the honest
     * Session-screen header.
     */
    case maskShifted(mask: String, mode: String
    )
    /**
     * A salt was fixed this turn — the condensation moment. Derived from the
     * `fix_salt` tool's own `AcpUpdate::ToolResult` (its real `realization_id`
     * and spiral `child_thread_id`), and carrying the fixed salt's TEXT so the
     * Session screen can render the gold moment directly, without a second
     * store read. Falls back to the newest grain only if a result is missing.
     */
    case condensation(realizationId: String, childThreadId: String?, text: String
    )
    /**
     * The turn reached its natural end (`AcpUpdate::TurnComplete`).
     */
    case turnComplete
    /**
     * **Bridge-synthesized.** The turn failed (`run_turn` returned `Err`).
     * Surfaced instead of unwinding across the FFI boundary.
     */
    case error(message: String
    )





}

#if compiler(>=6)
extension SessionEvent: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeSessionEvent: FfiConverterRustBuffer {
    typealias SwiftType = SessionEvent

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SessionEvent {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .textDelta(text: try FfiConverterString.read(from: &buf), register: try FfiConverterTypeReplyRegister.read(from: &buf)
        )
        
        case 2: return .toolCall(kind: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .maskShifted(mask: try FfiConverterString.read(from: &buf), mode: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .condensation(realizationId: try FfiConverterString.read(from: &buf), childThreadId: try FfiConverterOptionString.read(from: &buf), text: try FfiConverterString.read(from: &buf)
        )
        
        case 5: return .turnComplete
        
        case 6: return .error(message: try FfiConverterString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: SessionEvent, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .textDelta(text,register):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(text, into: &buf)
            FfiConverterTypeReplyRegister.write(register, into: &buf)
            
        
        case let .toolCall(kind):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(kind, into: &buf)
            
        
        case let .maskShifted(mask,mode):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(mask, into: &buf)
            FfiConverterString.write(mode, into: &buf)
            
        
        case let .condensation(realizationId,childThreadId,text):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(realizationId, into: &buf)
            FfiConverterOptionString.write(childThreadId, into: &buf)
            FfiConverterString.write(text, into: &buf)
            
        
        case .turnComplete:
            writeInt(&buf, Int32(5))
        
        
        case let .error(message):
            writeInt(&buf, Int32(6))
            FfiConverterString.write(message, into: &buf)
            
        }
    }
}


